package pe.org.camaracomercioica.protestos.exception; import jakarta.servlet.http.HttpServletRequest; import org.springframework.http.*; import org.springframework.security.access.AccessDeniedException; import org.springframework.web.bind.MethodArgumentNotValidException; import org.springframework.web.bind.annotation.*; import org.springframework.web.multipart.MaxUploadSizeExceededException; import java.time.Instant; import java.util.*; import java.util.stream.Collectors; @RestControllerAdvice public class GlobalExceptionHandler {@ExceptionHandler(ResourceNotFoundException.class) ResponseEntity<ApiError> notFound(ResourceNotFoundException e,HttpServletRequest r){return build(404,"NOT_FOUND",e.getMessage(),r,Map.of());}@ExceptionHandler({BadRequestException.class,MaxUploadSizeExceededException.class}) ResponseEntity<ApiError> bad(RuntimeException e,HttpServletRequest r){return build(400,"BAD_REQUEST",e.getMessage(),r,Map.of());}@ExceptionHandler(AccessDeniedException.class) ResponseEntity<ApiError> forbidden(AccessDeniedException e,HttpServletRequest r){return build(403,"FORBIDDEN","No tiene permisos para esta operación",r,Map.of());}@ExceptionHandler(MethodArgumentNotValidException.class) ResponseEntity<ApiError> validation(MethodArgumentNotValidException e,HttpServletRequest r){var errors=e.getBindingResult().getFieldErrors().stream().collect(Collectors.toMap(x->x.getField(),x->Optional.ofNullable(x.getDefaultMessage()).orElse("Inválido"),(a,b)->a,LinkedHashMap::new));return build(400,"VALIDATION_ERROR","Datos inválidos",r,errors);}@ExceptionHandler(Exception.class) ResponseEntity<ApiError> generic(Exception e,HttpServletRequest r){return build(500,"INTERNAL_ERROR","Ocurrió un error inesperado",r,Map.of());}private ResponseEntity<ApiError> build(int s,String c,String m,HttpServletRequest r,Map<String,String> errors){return ResponseEntity.status(s).body(new ApiError(Instant.now(),s,c,m,r.getRequestURI(),errors));}}
